import React from "react";
import { useForm } from "react-hook-form";
import { useNavigate } from "react-router-dom";

const AddCar = () => {
  const navigate = useNavigate();
  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm();

  const onSubmit = (data) => {
    console.log(data);
    alert("Thêm xe thành công!");
    navigate("/admin/cars");
  };

  return (
    <div className="admin-content">
      <h4>Thêm xe</h4>

      <form onSubmit={handleSubmit(onSubmit)}>
        {/* NAME */}
        <div className="mb-3">
          <label>Tên xe</label>
          <input
            className="form-control"
            {...register("name", { required: "Không được bỏ trống" })}
          />
          {errors.name && <p className="text-danger">{errors.name.message}</p>}
        </div>

        {/* TYPE */}
        <div className="mb-3">
          <label>Loại xe</label>
          <select
            className="form-control"
            {...register("type", { required: "Chọn loại xe" })}
          >
            <option value="">-- Chọn --</option>
            <option value="Số sàn">Số sàn</option>
            <option value="Tự động">Tự động</option>
          </select>
          {errors.type && <p className="text-danger">{errors.type.message}</p>}
        </div>

        {/* SEATS */}
        <div className="mb-3">
          <label>Số chỗ</label>
          <input
            type="number"
            className="form-control"
            {...register("seats", {
              required: "Nhập số chỗ",
              min: { value: 2, message: "Ít nhất 2 chỗ" },
            })}
          />
          {errors.seats && (
            <p className="text-danger">{errors.seats.message}</p>
          )}
        </div>

        <button className="btn btn-success">
          <i className="bi bi-check"></i> Lưu
        </button>
      </form>
    </div>
  );
};

export default AddCar;
